import{_ as d,c as e,o as a,ag as o}from"./chunks/framework.Cycwnjj0.js";const m=JSON.parse('{"title":"Git 基础","description":"","frontmatter":{},"headers":[],"relativePath":"tutorial/Note/Git/note.md","filePath":"tutorial/Note/Git/note.md","lastUpdated":1762784724000}'),r={name:"tutorial/Note/Git/note.md"};function i(c,t,l,g,h,n){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="git-基础" tabindex="-1">Git 基础 <a class="header-anchor" href="#git-基础" aria-label="Permalink to &quot;Git 基础&quot;">​</a></h1><p>git 是一个分布式版本控制工具</p><h2 id="git-基础命令" tabindex="-1">Git 基础命令 <a class="header-anchor" href="#git-基础命令" aria-label="Permalink to &quot;Git 基础命令&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>git -v</code></td><td>查看版本</td></tr><tr><td><code>git init</code></td><td>初始化仓库</td></tr><tr><td><code>git clone &lt;URL&gt;</code></td><td>克隆远程仓库</td></tr><tr><td><code>git config user.name &lt;Name&gt;</code></td><td>配置用户名</td></tr><tr><td><code>git config user.email &lt;Email&gt;</code></td><td>配置邮箱</td></tr><tr><td><code>git config --global user.name &lt;Name&gt;</code></td><td>全局配置用户名</td></tr><tr><td><code>git config --global user.email&lt;Email&gt;</code></td><td>全局配置邮箱</td></tr></tbody></table><h2 id="文件操作" tabindex="-1">文件操作 <a class="header-anchor" href="#文件操作" aria-label="Permalink to &quot;文件操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>git status</code></td><td>查看暂存区状态</td></tr><tr><td><code>git log</code></td><td>查看全部提交记录,详细信息</td></tr><tr><td><code>git log --oneline</code></td><td>查看全部提交记录,摘要信息</td></tr><tr><td><code>git log &lt;版本号&gt;</code></td><td>查看指定版本提交记录</td></tr><tr><td><code>git add &lt;FileName&gt;</code></td><td>提交到暂存区</td></tr><tr><td><code>git rm --cached &lt;FileName&gt;</code></td><td>从暂存区删除文件（解除跟踪），本地文件不会被删除</td></tr><tr><td><code>git rm -r --cached &lt;FileName&gt;</code></td><td>从暂存区递归删除整个目录</td></tr><tr><td><code>git commit -m &lt;Describe&gt;</code></td><td>语义化提交信息（Conventional Commits），提交到本地仓库</td></tr><tr><td><code>git restore &lt;FileName&gt;</code></td><td>恢复文件(add 操作之前的文件)</td></tr><tr><td><code>git reset --hard &lt;版本号&gt;</code></td><td>重置到指定版本,不保存提交记录</td></tr><tr><td><code>git revert &lt;版本号&gt;</code></td><td>恢复到指定版本的前一个版本,保存提交记录</td></tr></tbody></table><h2 id="分支操作" tabindex="-1">分支操作 <a class="header-anchor" href="#分支操作" aria-label="Permalink to &quot;分支操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>git branch &lt;Name&gt;</code></td><td>创建新分支(必须有提交记录才能创建)</td></tr><tr><td><code>git branch -v</code></td><td>查看分支列表</td></tr><tr><td><code>git checkout &lt;Name&gt;</code></td><td>切换分支</td></tr><tr><td><code>git checkout -b &lt;Name&gt;</code></td><td>创建分支并切换分支</td></tr><tr><td><code>git branch -d &lt;Name&gt;</code></td><td>删除分支</td></tr><tr><td><code>git merge &lt;Name&gt;</code></td><td>合并分支到当前分支(main)</td></tr></tbody></table><h2 id="标签操作" tabindex="-1">标签操作 <a class="header-anchor" href="#标签操作" aria-label="Permalink to &quot;标签操作&quot;">​</a></h2><p>给指定的版本号取别名,可代替版本号,可以很方便根据标签创建分支</p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>git tag</code></td><td>提交历史标签列表</td></tr><tr><td><code>git tag &lt;tagName&gt; &lt;版本号&gt;</code></td><td>给指定版本打标签(别名)</td></tr><tr><td><code>git log &lt;tagName&gt;</code></td><td>查看指定标签提交记录</td></tr><tr><td><code>git tag -d &lt;tagName&gt;</code></td><td>删除指定标签</td></tr></tbody></table><h2 id="远程操作" tabindex="-1">远程操作 <a class="header-anchor" href="#远程操作" aria-label="Permalink to &quot;远程操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>git push origin</code></td><td>推送到远程仓库</td></tr><tr><td><code>git pull origin</code></td><td>拉取远程仓库到本地</td></tr></tbody></table>',13)])])}const s=d(r,[["render",i]]);export{m as __pageData,s as default};
